@Composable
fun JobRoute(vm: JobViewModel) {
    val jobs = vm.jobs.collectAsLazyPagingItems()
    JobList(
        jobs = jobs,
        onRetry = jobs::retry,
        onBookmark = vm::toggleBookmark
    )
}

@Composable
fun JobList(items: List<JobUi>, onOpen: (String) -> Unit) {
    LazyColumn {
        items(items, key = { it.id }, contentType = { "job" }) { job ->
            JobRow(job = job, onClick = { onOpen(job.id) })
        }
    }
}

val showScrollTop by remember {
    derivedStateOf { listState.firstVisibleItemIndex > 2 }
}

LaunchedEffect(listState) {
    snapshotFlow { listState.firstVisibleItemIndex }
        .distinctUntilChanged()
        .collect(analytics::onFirstVisibleChanged)
}
